import React, { useState } from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';  // Schimbăm Switch cu Routes și Redirect cu Navigate
import Sidebar from './components/Sidebar';
import Zoom from './components/Zoom';
import MicrosoftTeams from './components/MicrosoftTeams';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/chrome';
import FileExplorer from './components/FileExplorer';
import './App.css';

const App = () => {
  const [activeComponent, setActiveComponent] = useState(null);

  return (
    <Router>
      <div className="App">
        <Sidebar activeComponent={activeComponent} setActiveComponent={setActiveComponent} />

        {/* Folosim Routes în loc de Switch */}
        <Routes>
          <Route path="/" element={<FileExplorer />} />
          <Route path="/zoom" element={<Zoom />} />
          <Route path="/teams" element={<MicrosoftTeams />} />
          <Route path="/word" element={<MicrosoftWord />} />
          <Route path="/excel" element={<MicrosoftExcel />} />
          <Route path="/powerpoint" element={<PowerPoint />} />
          <Route path="/pdf" element={<PDFReader />} />
          <Route path="/chrome" element={<Chrome />} />
          {/* Folosim Navigate în loc de Redirect pentru a redirecționa la pagina principală */}
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
